function u(t){return t==null||t===""?"--":`¥${Number(t).toLocaleString()}`}function a(t){if(!t)return"--";const r=new Date(t);if(Number.isNaN(r.getTime()))return String(t);const e=r.getFullYear(),n=String(r.getMonth()+1).padStart(2,"0"),i=String(r.getDate()).padStart(2,"0"),o=String(r.getHours()).padStart(2,"0"),f=String(r.getMinutes()).padStart(2,"0");return`${e}-${n}-${i} ${o}:${f}`}function g(t){if(!t)return"--";const r=new Date(t),e=Date.now();if(Number.isNaN(r.getTime()))return String(t);const n=e-r.getTime();return n<60*1e3?"刚刚":n<3600*1e3?`${Math.floor(n/(60*1e3))}分钟前`:n<1440*60*1e3?`${Math.floor(n/(3600*1e3))}小时前`:a(t)}function s(t){return t===1?"可租":t===2?"锁定中":"不可预订"}export{g as a,a as b,u as f,s as g};
